#include <iostream>
#include <string>
#include <iomanip>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    // s = "hh:mm:ssAM" or "hh:mm:ssPM"
    int h = stoi(s.substr(0, 2));
    string mm = s.substr(3, 2);
    string ss = s.substr(6, 2);
    string ampm = s.substr(8, 2);

    if (ampm == "AM") {
        if (h == 12) h = 0;
    } else { // PM
        if (h != 12) h += 12;
    }

    cout << setw(2) << setfill('0') << h << ":"
         << mm << ":" << ss << "\n";

    return 0;
}
